    fn tiny_png_bytes() -> Vec<u8> {
        use image::ImageEncoder;

        let mut bytes = Vec::new();
        image::codecs::png::PngEncoder::new(&mut bytes)
            .write_image(
                &[
                    255, 0, 0, 0, 255, 0, //
                    0, 0, 255, 255, 255, 0,
                ],
                2,
                2,
                image::ExtendedColorType::Rgb8,
            )
            .expect("encode png");
        bytes
    }

    fn tiny_jpeg_bytes() -> Vec<u8> {
        use image::ImageEncoder;

        let mut bytes = Vec::new();
        image::codecs::jpeg::JpegEncoder::new(&mut bytes)
            .write_image(
                &[
                    255, 0, 0, 0, 255, 0, //
                    0, 0, 255, 255, 255, 0,
                ],
                2,
                2,
                image::ExtendedColorType::Rgb8,
            )
            .expect("encode jpeg");
        bytes
    }

    #[test]
    fn emits_valid_pdf_header_and_trailer() {
        let layout = layout_text("hello pdf", LayoutOptions::default());
        let pdf = render_pdf(&layout);
        let text = String::from_utf8_lossy(&pdf);

        assert!(text.starts_with("%PDF-1.4"));
        assert!(text.contains("trailer << /Size "));
        assert!(text.contains("/Type /Page"));
    }

    #[test]
    fn renders_multiple_pages() {
        let layout = layout_text(
            "a\nb\nc\nd\ne",
            LayoutOptions {
                chars_per_line: 10,
                lines_per_page: 2,
                ..LayoutOptions::default()
            },
        );
        let pdf = render_pdf(&layout);
        let text = String::from_utf8_lossy(&pdf);

        assert!(text.contains("/Count 3"));
    }

    #[test]
    fn escapes_pdf_sensitive_characters_in_stream() {
        let layout = layout_text(r#"hello (pdf) \ world"#, LayoutOptions::default());
        let pdf = render_pdf(&layout);
        let text = String::from_utf8_lossy(&pdf);

        assert!(text.contains(r#"(hello \(pdf\) \\ world) Tj"#));
    }

    #[test]
    fn transliterates_latin_unicode_for_extractable_pdf_text() {
        let layout = layout_text(
            "François CentraleSupélec Saarbrücken Física Víctor α β ﬁeld co\u{00ad}author",
            LayoutOptions {
                chars_per_line: 200,
                ..LayoutOptions::default()
            },
        );
        let pdf = render_pdf(&layout);
        let text = String::from_utf8_lossy(&pdf);

        assert!(
            text.contains(
                "(Francois CentraleSupelec Saarbrucken Fisica Victor alpha beta field coauthor) Tj"
            ),
            "{text}"
        );
        for hidden in [
            "François",
            "Supélec",
            "Saarbrücken",
            "ﬁeld",
            "co\u{00ad}author",
        ] {
            assert!(!text.contains(hidden), "{hidden} leaked in {text}");
        }
    }

    #[test]
    fn emits_one_text_draw_per_line() {
        let layout = layout_text(
            "alpha\nbeta\ngamma",
            LayoutOptions {
                chars_per_line: 20,
                lines_per_page: 10,
                ..LayoutOptions::default()
            },
        );
        let pdf = render_pdf(&layout);
        let text = String::from_utf8_lossy(&pdf);

        assert_eq!(text.matches(" Tj ").count(), 3);
        assert_eq!(text.matches("T* ").count(), 2);
    }

